import { redirect } from "next/navigation";
import { getSession } from "@/lib/auth/session";
import { prisma } from "@/lib/db/prisma";
import styles from "./calendar.module.css";

export default async function CalendarPage() {
  const user = await getSession();

  if (!user || user.role !== "admin") {
    redirect("/login");
  }

  const rules = await prisma.scheduleRule.findMany({
    orderBy: { validFrom: "desc" },
    take: 5,
  });

  const exceptions = await prisma.calendarException.findMany({
    orderBy: { date: "desc" },
    take: 20,
  });

  const daysOfWeek = ["", "Lunes", "Martes", "Miercoles", "Jueves", "Viernes", "Sabado", "Domingo"];

  return (
    <main className={styles.container}>
      <h1 className={styles.title}>Gestion de Calendario</h1>

      <section className={styles.section}>
        <h2>Reglas de Agenda Activas</h2>
        {rules.length === 0 ? (
          <p className={styles.empty}>No hay reglas configuradas. Se usa el default (Viernes 08:30 - 11:50, 20 turnos).</p>
        ) : (
          <ul className={styles.list}>
            {rules.map((rule) => (
              <li key={rule.id} className={styles.ruleCard}>
                <strong>Vigente desde:</strong> {rule.validFrom.toLocaleDateString("es-AR")}<br />
                <strong>Dia:</strong> {daysOfWeek[rule.dayOfWeek]}<br />
                <strong>Horario:</strong> {rule.startTime} - {rule.endTime}<br />
                <strong>Turnos:</strong> {rule.slotCount}
              </li>
            ))}
          </ul>
        )}
      </section>

      <section className={styles.section}>
        <h2>Crear Nueva Regla</h2>
        <form action="/api/admin/schedule-rules" method="POST" className={styles.form}>
          <label>
            Vigente desde:
            <input type="date" name="validFrom" required />
          </label>
          <label>
            Dia de la semana:
            <select name="dayOfWeek" required>
              <option value="1">Lunes</option>
              <option value="2">Martes</option>
              <option value="3">Miercoles</option>
              <option value="4">Jueves</option>
              <option value="5">Viernes</option>
            </select>
          </label>
          <label>
            Hora inicio:
            <input type="time" name="startTime" defaultValue="09:00" required />
          </label>
          <label>
            Hora fin:
            <input type="time" name="endTime" defaultValue="14:00" required />
          </label>
          <label>
            Cantidad de turnos:
            <input type="number" name="slotCount" defaultValue={20} min={1} required />
          </label>
          <button type="submit" className={styles.button}>Crear Regla</button>
        </form>
      </section>

      <section className={styles.section}>
        <h2>Cancelar Dia</h2>
        <form action="/api/admin/calendar/day" method="POST" className={styles.form}>
          <input type="hidden" name="_method" value="DELETE" />
          <label>
            Fecha a cancelar:
            <input type="date" name="date" required />
          </label>
          <button type="submit" className={styles.dangerButton}>Cancelar Dia y Reprogramar</button>
        </form>
      </section>

      <section className={styles.section}>
        <h2>Excepciones Recientes</h2>
        {exceptions.length === 0 ? (
          <p className={styles.empty}>No hay excepciones registradas.</p>
        ) : (
          <ul className={styles.list}>
            {exceptions.map((ex) => (
              <li key={ex.id} className={styles.exceptionCard}>
                <strong>Fecha:</strong> {ex.date.toLocaleDateString("es-AR")}<br />
                <strong>Tipo:</strong> {ex.type}<br />
                <strong>Motivo:</strong> {ex.label}
              </li>
            ))}
          </ul>
        )}
      </section>
    </main>
  );
}
